			_, _ = fmt.Fprintf(runtime.Log,
				"operator attention: failed to commit durable audit outputs for %s; stopping work. %v\n",
				candidateID,
				err,
			)
		}
		emit("loop.operator_attention", map[string]any{
			"reason":       "durable_audit_commit_failed",
			"bead_id":      candidateID,
