	assert.Contains(t, out, "30 beads blocked behind 3 needs-human blockers")
	assert.Contains(t, out, "1. ddx-human-1 Needs human 1 (10 downstream)")
	assert.Contains(t, out, "2. ddx-human-2 Needs human 2 (10 downstream)")
